code = """import pandas as pd
import json

# Load data (using previous filtered variables if possible, but safer to reload from source or dataframe)
# I will reconstruct from storage
with open(locals()['var_function-call-8453869133508763863'], 'r') as f:
    cases_data = json.load(f)
accounts_data = locals()['var_function-call-8453869133508767072']

df_cases = pd.DataFrame(cases_data)
df_accounts = pd.DataFrame(accounts_data)

df_accounts['Id'] = df_accounts['Id'].astype(str).str.replace(r'^#', '', regex=True)
df_accounts['ShippingState'] = df_accounts['ShippingState'].astype(str).str.strip()
df_cases['accountid'] = df_cases['accountid'].astype(str).str.replace(r'^#', '', regex=True)
df_cases['createddate'] = pd.to_datetime(df_cases['createddate'], utc=True)
df_cases['closeddate'] = pd.to_datetime(df_cases['closeddate'], utc=True)

# Calculate duration in seconds
df_cases['duration_seconds'] = (df_cases['closeddate'] - df_cases['createddate']).dt.total_seconds()

# Merge
merged = pd.merge(df_cases, df_accounts, left_on='accountid', right_on='Id', how='inner')

# Define windows
today = pd.Timestamp('2022-10-26').tz_localize('UTC')

# Rolling 18 months
start_rolling = today - pd.DateOffset(months=18)
mask_rolling = (merged['closeddate'] >= start_rolling) & (merged['closeddate'] <= today + pd.Timedelta(days=1))
df_rolling = merged[mask_rolling]
res_rolling = df_rolling.groupby('ShippingState')['duration_seconds'].agg(['mean', 'count']).sort_values('mean')

# Last 6 completed quarters (Q2 2021 - Q3 2022)
# Q3 2022 ends Sep 30, 2022.
# Q2 2021 starts Apr 1, 2021.
start_fiscal = pd.Timestamp('2021-04-01').tz_localize('UTC')
end_fiscal = pd.Timestamp('2022-09-30 23:59:59.999999').tz_localize('UTC')
mask_fiscal = (merged['closeddate'] >= start_fiscal) & (merged['closeddate'] <= end_fiscal)
df_fiscal = merged[mask_fiscal]
res_fiscal = df_fiscal.groupby('ShippingState')['duration_seconds'].agg(['mean', 'count']).sort_values('mean')

print("__RESULT__:")
print(json.dumps({
    'rolling_top': res_rolling.head(5).to_dict(),
    'fiscal_top': res_fiscal.head(5).to_dict()
}))"""

